import { Controller } from '../decorators/controller.decorator';
import { Get, Post } from '../decorators/route.decorator';
import { Request, Response } from 'express';
import { accountService } from '../services/account.service';

@Controller('/api/account')
export class AccountController {

  // 现有方法 1: 获取余额
  @Get('/balance/:userId')
  async getBalance(req: Request, res: Response): Promise<void> {
    try {
      const { userId } = req.params;
      const result = await accountService.getBalance(userId);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  }

  // 现有方法 2: 获取交易记录
  @Get('/transactions/:userId')
  async getTransactions(req: Request, res: Response): Promise<void> {
    try {
      const { userId } = req.params;
      const result = await accountService.getTransactions(userId);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  }

  // 新增方法 1: 创建账户
  @Post('/create')
  async createAccount(req: Request, res: Response): Promise<void> {
    try {
      const { userId, initialBalance = 0 } = req.body;

      if (!userId || typeof userId !== 'string') {
        res.status(400).json({ success: false, error: '无效的用户ID' });
        return;
      }

      const result = await accountService.createAccount(userId, initialBalance);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  }

  // 新增方法 2: 存款
  @Post('/deposit')
  async deposit(req: Request, res: Response): Promise<void> {
    try {
      const { userId, amount } = req.body;

      if (!userId || typeof amount !== 'number' || amount <= 0) {
        res.status(400).json({ success: false, error: '无效的参数' });
        return;
      }

      const result = await accountService.deposit(userId, amount);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  }

  // 新增方法 3: 取款
  @Post('/withdraw')
  async withdraw(req: Request, res: Response): Promise<void> {
    try {
      const { userId, amount } = req.body;

      if (!userId || typeof amount !== 'number' || amount <= 0) {
        res.status(400).json({ success: false, error: '无效的参数' });
        return;
      }

      const result = await accountService.withdraw(userId, amount);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  }

  // 新增方法 4: 转账
  @Post('/transfer')
  async transfer(req: Request, res: Response): Promise<void> {
    try {
      const { fromUserId, toUserId, amount } = req.body;

      if (!fromUserId || !toUserId || typeof amount !== 'number' || amount <= 0) {
        res.status(400).json({ success: false, error: '无效的参数' });
        return;
      }

      const result = await accountService.transfer(fromUserId, toUserId, amount);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  }

  // 新增方法 5: 冻结账户
  @Post('/freeze')
  async freezeAccount(req: Request, res: Response): Promise<void> {
    try {
      const { userId, reason } = req.body;

      if (!userId) {
        res.status(400).json({ success: false, error: '无效的用户ID' });
        return;
      }

      const result = await accountService.freezeAccount(userId, reason);
      res.json(result);
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
